     1→package config
     2→
     3→import (
     4→	"fmt"
     5→	"os"
     6→
     7→	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/service/resource"
     8→	"github.com/spf13/viper"
     9→)
    10→
    11→type Config struct {
    12→	Server        ServerConfig        `mapstructure:"server"`
    13→	Log           LogConfig           `mapstructure:"log"`
    14→	Auth          AuthConfig          `mapstructure:"auth"`
    15→	S3            S3Config            `mapstructure:"s3"`
    16→	Harbor        HarborConfig        `mapstructure:"harbor"`
    17→	K8s           K8sConfig           `mapstructure:"k8s"`
    18→	TDSC          TDSCConfig          `mapstructure:"tdsc"`
    19→	Resources     ResourcesConfig     `mapstructure:"resources"`
    20→	InitContainer InitContainerConfig `mapstructure:"initContainer"`
    21→}
    22→
    23→type ServerConfig struct {
    24→	Mode string `mapstructure:"mode"`
    25→}
    26→
    27→type LogConfig struct {
    28→	Level              string `mapstructure:"level"`
    29→	OutputPath         string `mapstructure:"outputPath"`
    30→	PrintRequestParams bool   `mapstructure:"printRequestParams"` // 是否打印请求参数
    31→	SkipFileOperations bool   `mapstructure:"skipFileOperations"` // 是否跳过文件上传/下载请求
    32→}
    33→
    34→type AuthConfig struct {
    35→	Enabled   bool       `mapstructure:"enabled"`  // 是否启用认证
    36→	AuthType  string     `mapstructure:"authType"` // 认证类型: "jwt" 或 "basic_auth"
    37→	JWTSecret string     `mapstructure:"jwtSecret"`
    38→	TokenTTL  int        `mapstructure:"tokenTtl"` // 秒
    39→	Users     []UserInfo `mapstructure:"users"`    // 预设用户列表
    40→}
    41→
    42→type UserInfo struct {
    43→	Username string `mapstructure:"username"`
    44→	Password string `mapstructure:"password"`
    45→	UserID   string `mapstructure:"userId"` // 可选，默认使用 username
    46→}
    47→
    48→type S3Config struct {
    49→	Endpoint  string `mapstructure:"endpoint"`
    50→	AccessKey string `mapstructure:"accessKey"`
    51→	SecretKey string `mapstructure:"secretKey"`
    52→	Bucket    string `mapstructure:"bucket"`
    53→	Region    string `mapstructure:"region"`
    54→}
    55→
    56→type HarborConfig struct {
    57→	URL      string `mapstructure:"url"`
    58→	Domain   string `mapstructure:"domain"`
    59→	Username string `mapstructure:"username"`
    60→	Password string `mapstructure:"password"`
    61→}
    62→
    63→type K8sConfig struct {
    64→	Kubeconfig string `mapstructure:"kubeconfig"`
    65→	Namespace  string `mapstructure:"namespace"`
    66→}
    67→
    68→type TDSCConfig struct {
    69→	Vol string `mapstructure:"vol"`
    70→	URL string `mapstructure:"url"`
    71→}
    72→
    73→type ResourcesConfig struct {
    74→	GPUTypes []resource.GPUType `mapstructure:"gpuTypes"`
    75→}
    76→
    77→type InitContainerConfig struct {
    78→	Image string `mapstructure:"image"`
    79→}
    80→
    81→func Load(path string) (*Config, error) {
    82→	viper.SetConfigFile(path)
    83→	viper.SetConfigType("yaml")
    84→
    85→	// 设置默认值
    86→	viper.SetDefault("server.mode", "debug")
    87→	viper.SetDefault("log.level", "info")
    88→	viper.SetDefault("log.outputPath", "stdout")
    89→	viper.SetDefault("log.printRequestParams", false)
    90→	viper.SetDefault("log.skipFileOperations", true)
    91→	viper.SetDefault("auth.tokenTtl", 3600)
    92→	viper.SetDefault("auth.authType", "jwt")
    93→	viper.SetDefault("auth.authType", "jwt")
    94→	viper.SetDefault("k8s.namespace", "default")
    95→	viper.SetDefault("initContainer.image", "gz01-srdart.srdcloud.cn/tdp-paas/tdp_paas-tap-snapshot-docker-local/dev-bootstrap:v1.0.1-rc2")
    96→
    97→	// 允许从环境变量读取
    98→	viper.AutomaticEnv()
    99→
   100→	if err := viper.ReadInConfig(); err != nil {
   101→		if _, ok := err.(viper.ConfigFileNotFoundError); !ok {
   102→			return nil, fmt.Errorf("error reading config file: %w", err)
   103→		}
   104→		// 配置文件不存在时使用默认值
   105→	}
   106→
   107→	var cfg Config
   108→	if err := viper.Unmarshal(&cfg); err != nil {
   109→		return nil, fmt.Errorf("error unmarshaling config: %w", err)
   110→	}
   111→
   112→	// 设置认证开关的默认值（如果配置文件中没有设置）
   113→	if !viper.IsSet("auth.enabled") {
   114→		if cfg.Server.Mode == "debug" {
   115→			cfg.Auth.Enabled = false
   116→		} else {
   117→			cfg.Auth.Enabled = true
   118→		}
   119→	}
   120→
   121→	// 从环境变量覆盖敏感信息
   122→	if jwtSecret := os.Getenv("JWT_SECRET"); jwtSecret != "" {
   123→		cfg.Auth.JWTSecret = jwtSecret
   124→	}
   125→	if s3Key := os.Getenv("S3_ACCESS_KEY"); s3Key != "" {
   126→		cfg.S3.AccessKey = s3Key
   127→	}
   128→	if s3Secret := os.Getenv("S3_SECRET_KEY"); s3Secret != "" {
   129→		cfg.S3.SecretKey = s3Secret
   130→	}
   131→	if harborPass := os.Getenv("HARBOR_PASSWORD"); harborPass != "" {
   132→		cfg.Harbor.Password = harborPass
   133→	}
   134→	if authEnabled := os.Getenv("AUTH_ENABLED"); authEnabled != "" {
   135→		if authEnabled == "true" {
   136→			cfg.Auth.Enabled = true
   137→		} else if authEnabled == "false" {
   138→			cfg.Auth.Enabled = false
   139→		}
   140→	}
   141→
   142→	// 验证认证类型
   143→	if cfg.Auth.Enabled && cfg.Auth.AuthType != "jwt" && cfg.Auth.AuthType != "basic_auth" {
   144→		return nil, fmt.Errorf("invalid auth_type: %s, must be 'jwt' or 'basic_auth'", cfg.Auth.AuthType)
   145→	}
   146→
   147→	return &cfg, nil
   148→}
